var order = msg.payload.order;
var data  = msg.payload.data;
var commandToSend = '';

// --- Movimiento calibrado (respeta límites de posición) ---
if      (order === 'open')  { commandToSend = 'a'; }
else if (order === 'close') { commandToSend = 'z'; }
else if (order === 'stop')  { commandToSend = 's'; }
else if (order === 'goto') {
    if (data !== undefined && data !== null) {
        commandToSend = 'm' + data;
    } else {
        node.warn('Comando GOTO recibido sin datos');
        return null;
    }
}

// --- Movimiento libre (sin límites — panel admin) ---
else if (order === 'openFree')  { commandToSend = 'u'; }
else if (order === 'closeFree') { commandToSend = 'd'; }

// --- Reset de errores del variador ---
else if (order === 'resetVfd') { commandToSend = 'R'; }

// --- Anticipación de freno (pulsos) ---
else if (order === 'anticipacion') {
    if (data !== undefined && data !== null) {
        commandToSend = 'A' + data;
    } else {
        node.warn('Comando anticipacion recibido sin datos');
        return null;
    }
}

// --- Calibración manual paso a paso ---
else if (order === 'calibrar')     { commandToSend = 'c'; }
else if (order === 'setZero')      { commandToSend = '0'; }
else if (order === 'set100')       { commandToSend = '1'; }
else if (order === 'finCalibrado') { commandToSend = 'f'; }

else {
    node.warn('Orden desconocida: ' + order);
    return null;
}

msg.payload = commandToSend;
msg.retain  = false;
return msg;
